input.command:
SSH="ssh -i /home/agent/.ssh/id_ed25519 -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null -o ConnectTimeout=15 -p 22 audit@target-svc-readable-689bee.grundschutz-lab.svc.cluster.local"
$SSH 'echo "=== login.defs ENCRYPT/PASS ==="; grep -Ei "^(ENCRYPT_METHOD|PASS_MAX_DAYS|PASS_MIN_DAYS|SHA_CRYPT)" /etc/login.defs 2>/dev/null;
echo; echo "=== PAM common-password ==="; grep -v "^#" /etc/pam.d/common-password 2>/dev/null | grep -v "^$";
echo; echo "=== sshd effective (read-only) ==="; sshd -T 2>/dev/null | grep -Ei "passwordauthentication|permitrootlogin|pubkeyauthentication|permitemptypasswords|challengeresponse|kbdinteractive" || echo "sshd -T not permitted";
echo; echo "=== sshd_config files ==="; grep -RrEi "passwordauthentication|permitrootlogin|permitemptypasswords|pubkeyauthentication" /etc/ssh/sshd_config /etc/ssh/sshd_config.d/ 2>/dev/null;
echo; echo "=== empty-password scan (awk on shadow) ==="; sudo -n cat /etc/shadow | awk -F: "(\$2==\"\"){print \"EMPTY: \" \$1}"; echo "(keine Ausgabe = keine leeren Passwoerter)"'
